// CLX Error Monitor — Evaluate Thresholds
// Inputs: thresholds (from Load Thresholds), errors (from Load Recent Errors)

const thresholdsRaw = $('Load Thresholds').all();
const errorsRaw = $input.item.json;

const thresholds = (Array.isArray(thresholdsRaw) && thresholdsRaw.length > 0 && Array.isArray(thresholdsRaw[0].json)) ? thresholdsRaw[0].json : (Array.isArray(thresholdsRaw) ? thresholdsRaw.map(r => r.json) : []);
const errors = Array.isArray(errorsRaw) ? errorsRaw : [];

const now = Date.now();
const alerts = [];

for (const t of thresholds) {
  if (!t.error_code) continue;
  const windowMs = (t.window_minutes || 10) * 60 * 1000;
  const cutoff = now - windowMs;
  const matching = errors.filter(e =>
    e.error_code === t.error_code &&
    new Date(e.created_at).getTime() >= cutoff
  );
  if (matching.length >= (t.count_threshold || 5)) {
    alerts.push({
      error_code: t.error_code,
      severity: t.severity || 'warning',
      window_minutes: t.window_minutes || 10,
      count: matching.length,
      threshold: t.count_threshold || 5,
      sample_workflow: matching[0].workflow_name,
      sample_node: matching[0].node_name
    });
  }
}

return { json: { alert_count: alerts.length, alerts, checked_at: new Date().toISOString() } };

// Build alert email via raw MIME (same attribution-free pattern as Outreach Sender)
const data = $input.item.json;
const alerts = data.alerts || [];
const to = 'adesholaakintunde@gmail.com';
const fromName = 'Crystallux Monitor';
const fromEmail = 'info@crystallux.org';

const subject = '[CLX Alert] ' + alerts.length + ' threshold(s) exceeded — ' + alerts.map(a => a.error_code).join(', ');

const rows = alerts.map(a =>
  '<tr><td style="padding:6px;border:1px solid #ddd;">' + a.error_code + '</td>' +
  '<td style="padding:6px;border:1px solid #ddd;">' + a.severity + '</td>' +
  '<td style="padding:6px;border:1px solid #ddd;text-align:right;">' + a.count + ' / ' + a.threshold + '</td>' +
  '<td style="padding:6px;border:1px solid #ddd;">' + a.window_minutes + ' min</td>' +
  '<td style="padding:6px;border:1px solid #ddd;font-size:11px;color:#666;">' + (a.sample_workflow || '') + ' / ' + (a.sample_node || '') + '</td></tr>'
).join('');

const htmlBody = '<div style="font-family:Arial,sans-serif;font-size:14px;color:#333;max-width:700px;">' +
  '<p><strong>' + alerts.length + ' monitoring threshold(s) exceeded</strong> at ' + data.checked_at + '.</p>' +
  '<table style="border-collapse:collapse;width:100%;">' +
  '<tr style="background:#f5f5f5;">' +
  '<th style="padding:6px;border:1px solid #ddd;text-align:left;">Error Code</th>' +
  '<th style="padding:6px;border:1px solid #ddd;text-align:left;">Severity</th>' +
  '<th style="padding:6px;border:1px solid #ddd;text-align:right;">Count / Threshold</th>' +
  '<th style="padding:6px;border:1px solid #ddd;text-align:left;">Window</th>' +
  '<th style="padding:6px;border:1px solid #ddd;text-align:left;">Sample</th>' +
  '</tr>' +
  rows +
  '</table></div>';

const encodedSubject = '=?UTF-8?B?' + Buffer.from(subject, 'utf8').toString('base64') + '?=';
const mime = [
  'From: "' + fromName + '" <' + fromEmail + '>',
  'To: ' + to,
  'Subject: ' + encodedSubject,
  'MIME-Version: 1.0',
  'Content-Type: text/html; charset=utf-8',
  'Content-Transfer-Encoding: 7bit',
  '',
  htmlBody
].join('\r\n');
const raw = Buffer.from(mime, 'utf8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');

return { json: { ...data, gmail_raw: raw } };
